{% raw %}
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <style>
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700&family=Lato:wght@300;400;700&display=swap');
        
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Lato', sans-serif;
            background: white;
            padding: 20px;
        }

        .card-container {
            width: 100%;
            max-width: 900px;
            margin: 0 auto;
            background: white;
            border: 2px solid #e0e0e0;
            border-radius: 16px;
            overflow: hidden;
        }

        .card-header {
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            padding: 40px;
            position: relative;
            overflow: hidden;
        }

        .card-header::before {
            content: '';
            position: absolute;
            top: -50%;
            right: -10%;
            width: 400px;
            height: 400px;
            background: rgba(255,255,255,0.1);
            border-radius: 50%;
        }

        .church-logo {
            width: 80px;
            height: 80px;
            background: white;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            margin: 0 auto 20px;
            box-shadow: 0 8px 25px rgba(0,0,0,0.2);
            position: relative;
            z-index: 1;
        }

        .church-logo svg {
            width: 50px;
            height: 50px;
            fill: #667eea;
        }

        .header-title {
            text-align: center;
            color: white;
            position: relative;
            z-index: 1;
        }

        .header-title h1 {
            font-family: 'Playfair Display', serif;
            font-size: 32px;
            font-weight: 700;
            margin-bottom: 8px;
        }

        .header-title p {
            font-size: 16px;
            opacity: 0.95;
            letter-spacing: 1px;
        }

        .card-body {
            padding: 40px;
        }

        .member-info {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 25px;
            margin-bottom: 35px;
            padding-bottom: 35px;
            border-bottom: 2px solid #f0f0f0;
        }

        .info-group {
            display: flex;
            flex-direction: column;
        }

        .info-label {
            font-size: 11px;
            text-transform: uppercase;
            letter-spacing: 1.5px;
            color: #999;
            margin-bottom: 6px;
            font-weight: 600;
        }

        .info-value {
            font-size: 18px;
            color: #333;
            font-weight: 600;
        }

        .stats-row {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 20px;
            margin-bottom: 30px;
        }

        .stat-card {
            background: #f8f9ff;
            padding: 20px;
            border-radius: 12px;
            border: 2px solid #e8ebff;
            text-align: center;
        }

        .stat-number {
            font-size: 24px;
            font-weight: 700;
            color: #667eea;
            margin-bottom: 5px;
        }

        .stat-label {
            font-size: 10px;
            text-transform: uppercase;
            letter-spacing: 1px;
            color: #999;
            font-weight: 600;
        }

        .total-section {
            background: linear-gradient(135deg, #f8f9ff 0%, #f0f2ff 100%);
            padding: 30px;
            border-radius: 16px;
            margin-bottom: 30px;
            border: 2px solid #e8ebff;
            text-align: center;
        }

        .total-label {
            font-size: 13px;
            color: #667eea;
            text-transform: uppercase;
            letter-spacing: 2px;
            margin-bottom: 10px;
            font-weight: 700;
        }

        .total-amount {
            font-size: 42px;
            font-weight: 700;
            color: #667eea;
            font-family: 'Playfair Display', serif;
        }

        .payment-history {
            margin-top: 25px;
        }

        .history-header {
            font-size: 16px;
            font-weight: 700;
            color: #333;
            margin-bottom: 15px;
            padding-left: 15px;
            border-left: 4px solid #667eea;
        }

        .history-table {
            width: 100%;
            border-collapse: collapse;
        }

        .history-table thead th {
            text-align: left;
            font-size: 10px;
            text-transform: uppercase;
            letter-spacing: 1.5px;
            color: #999;
            font-weight: 700;
            padding: 12px 10px;
            border-bottom: 2px solid #e0e0e0;
        }

        .history-table tbody td {
            padding: 14px 10px;
            color: #333;
            font-size: 13px;
            border-bottom: 1px solid #f0f0f0;
        }

        .history-table tbody tr:nth-child(even) {
            background: #f8f9fa;
        }

        .receipt-badge {
            display: inline-block;
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            color: white;
            padding: 3px 10px;
            border-radius: 15px;
            font-size: 10px;
            font-weight: 600;
            letter-spacing: 0.5px;
        }

        .card-footer {
            background: #f8f9fa;
            padding: 30px;
            text-align: center;
            border-top: 2px solid #e0e0e0;
        }

        .footer-text {
            color: #666;
            font-size: 12px;
            line-height: 1.8;
            margin-bottom: 12px;
        }

        .footer-verse {
            font-style: italic;
            color: #667eea;
            font-size: 13px;
            font-weight: 600;
            font-family: 'Playfair Display', serif;
        }

        @media print {
            body {
                padding: 0;
            }
            
            .card-container {
                border: none;
            }
        }
    </style>
</head>
<body>
    <div class="card-container">
        <!-- Header -->
        <div class="card-header">
            <div class="church-logo">
                <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                    <path d="M12 2L4 7v6.5C4 19 8 22 12 22s8-3 8-8.5V7l-8-5zm0 2.18l6 3.75v5.57c0 3.9-3.13 6.5-6 6.5s-6-2.6-6-6.5V7.93l6-3.75zM11 8v3H8v2h3v3h2v-3h3v-2h-3V8h-2z"/>
                </svg>
            </div>
            <div class="header-title">
                <h1>{{ company_name or "Ecclesia Church" }}</h1>
                <p>Member Tithe Record Certificate</p>
            </div>
        </div>

        <!-- Body -->
        <div class="card-body">
            <!-- Member Information -->
            <div class="member-info">
                <div class="info-group">
                    <span class="info-label">Member ID</span>
                    <span class="info-value">{{ member_id or "N/A" }}</span>
                </div>
                <div class="info-group">
                    <span class="info-label">Full Name</span>
                    <span class="info-value">{{ salutation or "" }} {{ full_name or "N/A" }}</span>
                </div>
                <div class="info-group">
                    <span class="info-label">Branch</span>
                    <span class="info-value">{{ branch or "Main Branch" }}</span>
                </div>
                <div class="info-group">
                    <span class="info-label">Record Date</span>
                    <span class="info-value">{{ record_date or frappe.utils.today() }}</span>
                </div>
            </div>

            <!-- Statistics -->
            <div class="stats-row">
                <div class="stat-card">
                    <div class="stat-number">{{ total_payments or 0 }}</div>
                    <div class="stat-label">Total Payments</div>
                </div>
                <div class="stat-card">
                    <div class="stat-number">{{ avg_payment or "₦0.00" }}</div>
                    <div class="stat-label">Average Payment</div>
                </div>
                <div class="stat-card">
                    <div class="stat-number">{{ last_payment_date or "N/A" }}</div>
                    <div class="stat-label">Last Payment</div>
                </div>
            </div>

            <!-- Total Amount -->
            <div class="total-section">
                <div class="total-label">Total Tithe Contributed</div>
                <div class="total-amount">{{ total_amount or "₦0.00" }}</div>
            </div>

            <!-- Payment History - Updated with all columns -->
            {% if recent_payments and recent_payments|length > 0 %}
            <div class="payment-history">
                <div class="history-header">Payment History</div>
                <table class="history-table">
                    <thead>
                        <tr>
                            <th>Date</th>
                            <th>Receipt No</th>
                            <th>Currency</th>
                            <th style="text-align: right;">Amount Paid</th>
                            <th style="text-align: center;">Exch. Rate</th>
                            <th style="text-align: right;">Amount (LCY)</th>
                        </tr>
                    </thead>
                    <tbody>
                        {% for payment in recent_payments %}
                        <tr>
                            <td>{{ payment.date or "N/A" }}</td>
                            <td><span class="receipt-badge">{{ payment.receipt_no or "N/A" }}</span></td>
                            <td>{{ payment.currency or "NGN" }}</td>
                            <td style="text-align: right;">{{ payment.amount_paid or "0.00" }}</td>
                            <td style="text-align: center;">{{ payment.exchange_rate or "1.00" }}</td>
                            <td style="font-weight: 700; color: #667eea; text-align: right;">{{ payment.amount_in_lc or "₦0.00" }}</td>
                        </tr>
                        {% endfor %}
                    </tbody>
                </table>
            </div>
            {% else %}
            <div class="payment-history">
                <div class="history-header">Payment History</div>
                <p style="text-align: center; color: #999; padding: 20px;">No payment records found.</p>
            </div>
            {% endif %}
        </div>

        <!-- Footer -->
        <div class="card-footer">
            <div class="footer-text">
                Thank you for your faithful giving and commitment to the work of God's kingdom.<br>
                Your contributions support our mission and ministry initiatives.
            </div>
            <div class="footer-verse">
                "Each of you should give what you have decided in your heart to give" - 2 Corinthians 9:7
            </div>
        </div>
    </div>
</body>
</html>
{% endraw %}
